    public class StackPool<T> : Stack<Stack<T>>
    {
        public Stack<T> Rent()
        {
            if (Count > 0)
                return Pop()!;
            return new Stack<T>();
        }

        public void Return(ref Stack<T> stack)
        {
            Return(stack);
            stack = null!;
        }

        public void Return(Stack<T>? stack)
        {
            if (stack == null)
                return;

            stack.Clear();
            Push(stack);
        }
    }

