using XamlX.Transform;

namespace Avalonia.Markup.Xaml.XamlIl.CompilerExtensions.Transformers
{
    class IgnoredDirectivesTransformer : IXamlAstTransformer
    {
        public IXamlAstNode Transform(AstTransformationContext context, IXamlAstNode node)
        {
            if (node is XamlAstObjectNode no)
            {
                foreach (var d in no.Children.OfType<XamlAstXmlDirective>().ToList())
                {
                    if (d.Namespace == XamlNamespaces.Xaml2006)
                    {
                        if (d.Name == "Precompile" ||
                            d.Name == "Class" ||
                            d.Name == "FieldModifier" ||
                            d.Name == "ClassModifier")
                            no.Children.Remove(d);
                    }
                }
            }

            return node;
        }
    }
}

using System;
using System.ComponentModel;
using System.Runtime.Serialization;
using GitHub.DistributedTask.Expressions2.Sdk;
using GitHub.Services.WebApi.Internal;

namespace GitHub.DistributedTask.ObjectTemplating.Tokens
{
    [DataContract]
    [ClientIgnore]
    [EditorBrowsable(EditorBrowsableState.Never)]
    public sealed class NullToken : LiteralToken, INull
    {
        public NullToken(
            Int32? fileId,
            Int32? line,
            Int32? column)
            : base(TokenType.Null, fileId, line, column)
        {
        }

        public override TemplateToken Clone(Boolean omitSource)
        {
            return omitSource ? new NullToken(null, null, null) : new NullToken(FileId, Line, Column);
        }

        public override String ToString()
        {
            return String.Empty;
        }
    }
}

using System.Runtime.Serialization;
using Newtonsoft.Json;

namespace GitHub.DistributedTask.WebApi
{
    [DataContract]
    public class AgentLabel
    {
        [JsonConstructor]
        public AgentLabel()
        {
        }

        public AgentLabel(string name)
        {
            this.Name = name;
            this.Type = LabelType.System;
        }

        public AgentLabel(string name, LabelType type)
        {
            this.Name = name;
            this.Type = type;
        }

        private AgentLabel(AgentLabel labelToBeCloned)
        {
            this.Id = labelToBeCloned.Id;
            this.Name = labelToBeCloned.Name;
            this.Type = labelToBeCloned.Type;
        }

        [DataMember]
        public int Id
        {
            get;
            set;
        }

        [DataMember]
        public string Name
        {
            get;
            set;
        }

        [DataMember]
        public LabelType Type
        {
            get;
            set;
        }

        public AgentLabel Clone()
        {
            return new AgentLabel(this);
        }
    }
}

using System;
using System.Collections;
using System.Collections.Generic;
using System.Linq;
using System.Runtime.Serialization;

namespace GitHub.DistributedTask.WebApi
{
    [DataContract]
    public sealed class TimelineRecordFeedLinesWrapper
    {
        public TimelineRecordFeedLinesWrapper()
        {
        }

        public TimelineRecordFeedLinesWrapper(Guid stepId, IList<string> lines)
        {
            this.StepId = stepId;
            this.Value = lines.ToList();
            this.Count = lines.Count;
        }

        public TimelineRecordFeedLinesWrapper(Guid stepId, IList<string> lines, Int64 startLine)
            : this(stepId, lines)
        {
            this.StartLine = startLine;
        }

        [DataMember(Order = 0)]
        public Int32 Count { get; private set; }

        [DataMember]
        public List<string> Value
        {
            get; private set;
        }

        [DataMember(EmitDefaultValue = false)]
        public Guid StepId { get; set; }

        [DataMember(EmitDefaultValue = false)]
        public Int64? StartLine { get; private set; }
    }
}
